1	const PROCESSING_FEE = 5;
2	
3	const basePremium = (item: { type: string }): number => {
4	  if (item.type === "sword") {
5	    return 100;
6	  }
7	  return 0;
8	};
9	
10	export const processSteps = (customer: unknown, steps: Array<{ op: string; items: Array<{ type: string }> }>): unknown => {
11	  return steps.map((step) => {
12	    const itemsTotal = step.items.reduce((sum, item) => sum + basePremium(item), 0);
13	    return { premium: itemsTotal + PROCESSING_FEE };
14	  });
15	};
